import{_ as a,o as s,c as d,a0 as e}from"./chunks/framework.jwovEGr5.js";const i="/assets/001_skillhub-info-skills_IzOlb7IQbo.C9lhe9n2.png",n="/assets/002_image_Y8tcbQ5zXo.B5gQvHxO.png",p="/assets/003_image_QIV7b3XORo.Dob5aSya.png",l="/assets/aihot-install.DDhhx19n.png",r="/assets/aihot-openai-result.DVFsL6o-.png",o="/assets/aihot-daily-report.CjG7nigL.png",k=JSON.parse('{"title":"第 15 章 资讯整合：把信息流变成每日通知 ​","description":"","frontmatter":{},"headers":[],"relativePath":"p2/15.md","filePath":"p2/15.md"}'),c={name:"p2/15.md"};function h(b,t,g,u,v,_){return s(),d("div",null,[...t[0]||(t[0]=[e(`<h1 id="第-15-章-资讯整合-把信息流变成每日通知-​" tabindex="-1">第 15 章 资讯整合：把信息流变成每日通知 ​ <a class="header-anchor" href="#第-15-章-资讯整合-把信息流变成每日通知-​" aria-label="Permalink to &quot;第 15 章 资讯整合：把信息流变成每日通知 ​&quot;">​</a></h1><p>资讯整合最怕两件事：一是信息太多，真正重要的内容被淹没；二是通知太吵，最后所有人都把它当背景噪音。</p><p>WorkBuddy 把多个信息源变成可筛选、可解释、可追踪的通知系统。比如，GitHub 热点项目每日通知、AIHOT 行业日报、论文与技术趋势追踪、公众号和博客监控、新闻与热榜舆情、事实核查与来源补证。</p><p>让用户每天少错过真正值得看的东西。</p><h2 id="资讯通知的共同工作流-​" tabindex="-1">资讯通知的共同工作流 ​ <a class="header-anchor" href="#资讯通知的共同工作流-​" aria-label="Permalink to &quot;资讯通知的共同工作流 ​&quot;">​</a></h2><p>无论是 GitHub 项目、AI 新闻、论文、政策还是热榜，稳定的资讯通知都可以拆成同一条链路：先收集，再去重，再筛选，再摘要，最后按人群和场景推送。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>flowchart LR</span></span>
<span class="line"><span>    A[订阅源与检索任务] --&gt; B[抓取与去重]</span></span>
<span class="line"><span>    B --&gt; C[分类与重要性评分]</span></span>
<span class="line"><span>    C --&gt; D[摘要、翻译和影响判断]</span></span>
<span class="line"><span>    D --&gt; E[来源补证与事实核查]</span></span>
<span class="line"><span>    E --&gt; F[生成通知卡片]</span></span>
<span class="line"><span>    F --&gt; G[推送到飞书、微信、邮件或文档]</span></span>
<span class="line"><span>    G --&gt; H[归档与复盘关键词]</span></span></code></pre></div><table tabindex="0"><thead><tr><th>环节</th><th>要解决什么</th><th>常见输出</th></tr></thead><tbody><tr><td>收集</td><td>从新闻、热榜、GitHub、arXiv、RSS、公众号、搜索引擎拉取候选内容。</td><td>候选列表、原始链接、发布时间、来源。</td></tr><tr><td>去重</td><td>同一事件可能被多个来源重复报道。</td><td>合并同源事件，保留首发和权威来源。</td></tr><tr><td>筛选</td><td>不是所有新内容都值得推送。</td><td>重要性评分、相关性评分、风险等级。</td></tr><tr><td>摘要</td><td>把长文章、论文、项目 README 转成可读摘要。</td><td>三句话摘要、影响判断、适用人群。</td></tr><tr><td>核查</td><td>避免把传闻、营销稿、错误信息当事实。</td><td>证据表、可信度、待确认项。</td></tr><tr><td>通知</td><td>用固定格式推送给对应人群。</td><td>飞书卡片、微信群消息、日报文档、邮件摘要。</td></tr></tbody></table><h2 id="可用的资讯类-skill-​" tabindex="-1">可用的资讯类 Skill ​ <a class="header-anchor" href="#可用的资讯类-skill-​" aria-label="Permalink to &quot;可用的资讯类 Skill ​&quot;">​</a></h2><p><img src="`+i+'" alt=""></p><p>大致可以分成六类：新闻、AI 行业、开发者趋势、科研论文、内容监控、事实核查与搜索补证。</p><table tabindex="0"><thead><tr><th>Skill / 工具</th><th>适合通知什么</th><th>本章怎么用</th></tr></thead><tbody><tr><td>腾讯新闻</td><td>国内外热点、早晚报、实时资讯、领域新闻。</td><td>适合做管理层早报、行业新闻通知、突发事件提醒。</td></tr><tr><td>AIHOT</td><td>AI 模型、产品、行业、论文动态。</td><td>适合做 AI 行业日报和团队技术雷达。</td></tr><tr><td>GitHub 热门项目</td><td>今日、本周、本月热门项目，支持语言过滤。</td><td>适合给研发团队做每日开源项目推荐。</td></tr><tr><td>GitHub AI 趋势追踪</td><td>GitHub AI 热门项目趋势报告。</td><td>适合做 AI 工程团队每周趋势简报。</td></tr><tr><td>ArXiv 论文追踪</td><td>最新研究论文搜索与总结。</td><td>适合研究、算法和产品策略团队跟踪论文动向。</td></tr><tr><td>新闻摘要</td><td>从 RSS 源获取新闻并生成摘要和语音播报。</td><td>适合固定源日报、行业资讯语音简报。</td></tr><tr><td>博客监控</td><td>监控博客和 RSS 订阅源更新。</td><td>适合关注竞品博客、官方 changelog、技术团队博客。</td></tr><tr><td>wechat-article-search</td><td>搜索公众号文章标题、摘要、发布时间、来源账号和链接。</td><td>适合监控行业 KOL、竞品公众号和爆款选题。</td></tr><tr><td>蜜度热搜榜</td><td>30+ 主流平台热搜数据，支持关键词、时间范围和榜单类型筛选。</td><td>适合做舆情预警、内容选题触发器。</td></tr><tr><td>Twitter 分析</td><td>Twitter 研究与内容情报分析。</td><td>适合跟踪海外 AI、开源、投资和产品讨论。</td></tr><tr><td>多引擎搜索 / Tavily / Exa / Perplexity / 元宝搜索标准版</td><td>多源搜索、深度研究、引用来源补证。</td><td>适合给重要新闻、论文、项目做二次验证。</td></tr><tr><td>jiaozhen-factcheck / 鹅厂辟谣助手</td><td>事实查证、谣言识别、腾讯相关辟谣辅助。</td><td>适合在通知前给争议信息加可信度判断。</td></tr></tbody></table><h2 id="github-热点项目每日通知-​" tabindex="-1">GitHub 热点项目每日通知 ​ <a class="header-anchor" href="#github-热点项目每日通知-​" aria-label="Permalink to &quot;GitHub 热点项目每日通知 ​&quot;">​</a></h2><p>比如：每天 9 点抓取 GitHub Trending 和 AI 热门项目。按语言、主题、star 增长、最近提交、license 过滤。只推送 Top 5-10 个，并给出“是否值得试用”的判断。</p><p>text</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span> 定时每天早上7点返回gthub热门项目，并输出项目大概简介</span></span></code></pre></div><p><img src="'+n+'" alt=""></p><p><img src="'+p+'" alt=""></p><h2 id="aihot-生成-ai-行业日报-​" tabindex="-1">AIHOT 生成 AI 行业日报 ​ <a class="header-anchor" href="#aihot-生成-ai-行业日报-​" aria-label="Permalink to &quot;AIHOT 生成 AI 行业日报 ​&quot;">​</a></h2><p>AI 行业信息更新快，AIHOT 可以作为一个现成的信息源。它面向 AI 动态提供精选内容，覆盖模型、产品、行业和论文等方向，并支持 Agent 使用。</p><p>比如：每天固定时间从 AIHOT 拉取 AI 动态。按模型、产品、行业、论文、开源项目、商业化分组。对每条内容做“影响范围、可信度、与本团队相关性”评分。只推送 5-8 条重点，其余进入文档归档。对高影响内容追加二次检索，补充原始链接或官方来源。</p><p>安装aihot skill，</p><p>Plain</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>帮我安装这个 skill：https://aihot.virxact.com/aihot-skill/</span></span></code></pre></div><p><img src="'+l+'" alt=""></p><p>text</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>请看一下最近 OpenAI 发布了什么新东西</span></span></code></pre></div><p><img src="'+r+'" alt=""></p><p>Plain</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>总结今日热点新闻，值关注AI大模型方向</span></span></code></pre></div><p><img src="'+o+'" alt=""></p><table tabindex="0"><thead><tr><th>日报模块</th><th>写什么</th><th>通知对象</th></tr></thead><tbody><tr><td>今日三件大事</td><td>最值得打扰所有人的变化。</td><td>全员或管理层。</td></tr><tr><td>模型与产品</td><td>新模型、新功能、新 API、新价格。</td><td>产品、研发、运营。</td></tr><tr><td>开源项目</td><td>可试用工具、框架、Agent 项目。</td><td>研发团队。</td></tr><tr><td>论文研究</td><td>可能影响技术路线的新方法。</td><td>算法、技术负责人。</td></tr><tr><td>机会与风险</td><td>竞品动作、替代方案、合规变化。</td><td>业务负责人。</td></tr></tbody></table>',32)])])}const A=a(c,[["render",h]]);export{k as __pageData,A as default};
